import { ChatFlow } from 'flowise/dist';

const PII_PATTERNS = [
  /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
  /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g,
  /\b\d{16}\b/g
];

function scanChatflowOutputs(flow: ChatFlow, executionData: any): string[] {
  const leaks: string[] = [];

  // Scan all node outputs
  Object.values(executionData.nodes || {}).forEach((nodeData: any) => {
    if (nodeData.output) {
      PII_PATTERNS.forEach(pattern => {
        const matches = nodeData.output.match(pattern);
        if (matches) {
          leaks.push(`Node ${nodeData.id}: ${matches.join(', ')}`);
        }
      });
    }
  });

  return leaks;
}

// Usage in Flowise callback
const result = scanChatflowOutputs(flow, chatflowResult);
if (result.length > 0) {
  console.error('PII Leaks Detected:', result);
}
