import { VectorStoreRetriever } from 'flowise/dist';

function detectSensitiveDocs(retrievedDocs: any[]): boolean {
  const SENSITIVE_TAGS = ['internal', 'confidential', 'employee', 'pii'];

  return retrievedDocs.some(doc => 
    doc.metadata?.tags?.some((tag: string) => SENSITIVE_TAGS.includes(tag)) ||
    doc.pageContent.match(/employee|ssn|confidential/i)
  );
}

// Hook into Document Retriever node
class SafeRetriever extends VectorStoreRetriever {
  async retrieve(query: string) {
    const docs = await super.retrieve(query);
    if (detectSensitiveDocs(docs)) {
      throw new Error('Sensitive documents detected in retrieval');
    }
    return docs;
  }
}
