type AgentContext = { input: string; output: string; piiDetected: boolean };

const agentContexts: AgentContext[] = [];

function trackAgentHandoff(flowExecution: any) {
  const handoffs = flowExecution.edges?.filter((edge: any) => 
    edge.source.includes('agent') && edge.target.includes('agent')
  ) || [];

  handoffs.forEach((handoff: any) => {
    const sourceOutput = flowExecution.nodes[handoff.source]?.output;
    const piiInSource = PII_PATTERNS.some(pattern => sourceOutput?.match(pattern));

    agentContexts.push({
      input: sourceOutput,
      output: flowExecution.nodes[handoff.target]?.input,
      piiDetected: piiInSource
    });
  });

  // Alert if PII flows between agents
  const leaks = agentContexts.filter(ctx => ctx.piiDetected && ctx.output?.includes(ctx.input?.slice(0, 50)));
  if (leaks.length > 0) {
    console.error('Agent handoff PII leak:', leaks);
  }
}
