import { ChatFlow } from 'flowise/dist';

const PII_REDACTOR = {
  email: '[EMAIL]',
  phone: '[PHONE]',
  ssn: '[SSN]'
};

function redactPII(text: string): string {
  let cleaned = text;
  cleaned = cleaned.replace(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, PII_REDACTOR.email);
  cleaned = cleaned.replace(/\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, PII_REDACTOR.phone);
  cleaned = cleaned.replace(/\b\d{3}-\d{2}-\d{4}\b/g, PII_REDACTOR.ssn);
  return cleaned;
}

// Global output wrapper
class SafeChatFlow extends ChatFlow {
  async run(inputs: any) {
    const result = await super.run(inputs);
    result.output = redactPII(result.output);
    return result;
  }
}

// Apply to flow configuration
chatflowConfig.nodes.forEach(node => {
  node.outputParser = (output: string) => redactPII(output);
});
