import { DocumentRetriever } from 'flowise/dist';

class SafeDocumentRetriever extends DocumentRetriever {
  async retrieve(query: string, filter?: any) {
    const docs = await super.retrieve(query, filter);

    // Filter out sensitive docs
    const safeDocs = docs.filter(doc => {
      const metadata = doc.metadata || {};
      return !metadata.sensitive && !metadata.internal;
    });

    if (safeDocs.length === 0 && docs.length > 0) {
      console.warn('All retrieved docs filtered as sensitive, using empty context');
    }

    return safeDocs;
  }
}

// Update flow configuration
const retrieverNode = chatflowConfig.nodes.find(n => n.type === 'DocumentRetriever');
if (retrieverNode) {
  retrieverNode.retriever = new SafeDocumentRetriever();
}
