class SanitizedAgentNode {
  sanitizeContext(context: any): any {
    return {
      ...context,
      memory: this.redactPII(context.memory),
      output: this.redactPII(context.output),
      session: this.redactPII(context.session)
    };
  }

  private redactPII(data: string): string {
    return data.replace(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, '[EMAIL]')
               .replace(/\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, '[PHONE]');
  }
}

// Wrap agent nodes
chatflowConfig.nodes
  .filter(node => node.type.includes('Agent'))
  .forEach(agentNode => {
    const originalExecute = agentNode.execute;
    agentNode.execute = async (...args: any[]) => {
      const result = await originalExecute.apply(agentNode, args);
      const sanitizer = new SanitizedAgentNode();
      return sanitizer.sanitizeContext(result);
    };
  });
