import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise/dist';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  project: 'flowise-pii-protection'
});

// Add Vex as Flowise callback handler
class VexProtectedChatFlow extends ChatFlow {
  async run(inputs: any) {
    // Vex pre-execution validation
    await vex.validateFlow(this.config, {
      rules: ['no-pii-leakage', 'vector-store-safety', 'agent-handoff-security']
    });

    const result = await super.run(inputs);

    // Vex post-execution validation
    const issues = await vex.scanExecution({
      flowConfig: this.config,
      executionData: result,
      detectors: ['pii-regex', 'sensitive-docs', 'context-leak']
    });

    if (issues.length > 0) {
      throw new Error(`Vex blocked unsafe execution: ${issues.map(i => i.type).join(', ')}`);
    }

    return result;
  }
}

// Install: npm install flowise @vex_dev/sdk
export { VexProtectedChatFlow as ChatFlow };
